namespace sv_d0f0459c801a483f9075f448f7124888.Client;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_d0f0459c801a483f9075f448f7124888.Client;

// Runs on WebAssembly. Reads auth state that was persisted by the server
// during prerendering, so the user's identity survives the WASM handoff.
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) && userInfo is not null)
        {
            var claims = new List<Claim>
            {
                new(ClaimTypes.Name, userInfo.Email),
                new(ClaimTypes.Email, userInfo.Email),
            };

            foreach (var role in userInfo.Roles)
            {
                claims.Add(new Claim(ClaimTypes.Role, role));
            }

            _authenticationStateTask = Task.FromResult(
                new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "PersistentAuth"))));
        }
        else
        {
            _authenticationStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_d0f0459c801a483f9075f448f7124888.Auth;

// Server-side provider that simulates a logged-in user with hardcoded claims.
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _state = Task.FromResult(CreateState());

    private static AuthenticationState CreateState()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name,  "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role,  "User"),
            new Claim(ClaimTypes.Role,  "Editor"),
        };

        var identity  = new ClaimsIdentity(claims, "HardcodedAuth");
        var principal = new ClaimsPrincipal(identity);
        return new AuthenticationState(principal);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _state;
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_d0f0459c801a483f9075f448f7124888.Client;
using System.Security.Claims;

namespace sv_d0f0459c801a483f9075f448f7124888.Auth;

// Subscribes to the PersistentComponentState persisting callback so that
// the authenticated user's info is serialised into the prerendered page.
// The client-side PersistentAuthenticationStateProvider then picks it up.
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    public override async Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        if (_authenticationStateTask is null)
            throw new InvalidOperationException("Authentication state has not been set. Call SetAuthenticationState first.");

        return await _authenticationStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value
                     ?? principal.FindFirst(ClaimTypes.Name)?.Value;
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            if (email is not null)
            {
                _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
                {
                    Email = email,
                    Roles = roles,
                });
            }
        }
    }

    public void Dispose() => _subscription.Dispose();
}

